set -euo pipefail
set -x

# Training data generated by examples/data_preprocess/openmathreasoning_hero.py
hero_train_path=${HERO_TRAIN_PATH:-$HOME/data/openmathreasoning_hero/train_mixed.parquet}
hero_val_path=${HERO_VAL_PATH:-$HOME/data/openmathreasoning_hero/val_mixed.parquet}

# Default to a single 8x24GB machine with training and dense RM colocated.
# These defaults are intentionally conservative so the first run is less likely to OOM.
model_path=${HERO_MODEL_PATH:-Qwen/Qwen3-4B-Base}
trainer_gpus=${HERO_TRAINER_GPUS_PER_NODE:-8}
trainer_nodes=${HERO_TRAINER_NNODES:-1}
train_batch_size=${HERO_TRAIN_BATCH_SIZE:-64}
max_prompt_length=${HERO_MAX_PROMPT_LENGTH:-1024}
max_response_length=${HERO_MAX_RESPONSE_LENGTH:-2048}
ppo_mini_batch_size=${HERO_PPO_MINI_BATCH_SIZE:-64}
ppo_micro_batch_size=${HERO_PPO_MICRO_BATCH_SIZE_PER_GPU:-2}
rollout_log_prob_micro_batch_size=${HERO_ROLLOUT_LOG_PROB_MICRO_BATCH_SIZE_PER_GPU:-2}
ref_log_prob_micro_batch_size=${HERO_REF_LOG_PROB_MICRO_BATCH_SIZE_PER_GPU:-2}
rollout_tp_size=${HERO_ROLLOUT_TP_SIZE:-2}
rollout_n=${HERO_ROLLOUT_N:-4}
rollout_gpu_memory_utilization=${HERO_ROLLOUT_GPU_MEMORY_UTILIZATION:-0.5}
rollout_max_num_seqs=${HERO_ROLLOUT_MAX_NUM_SEQS:-128}
rollout_max_num_batched_tokens=${HERO_ROLLOUT_MAX_NUM_BATCHED_TOKENS:-$((max_prompt_length + max_response_length))}
rm_enable_resource_pool=${HERO_RM_ENABLE_RESOURCE_POOL:-False}
rm_gpus=${HERO_RM_GPUS_PER_NODE:-8}
rm_nodes=${HERO_RM_NNODES:-1}
rm_tp_size=${HERO_RM_TP_SIZE:-2}
rm_gpu_memory_utilization=${HERO_RM_GPU_MEMORY_UTILIZATION:-0.5}
rm_prompt_length=${HERO_RM_PROMPT_LENGTH:-$max_prompt_length}
rm_response_length=${HERO_RM_RESPONSE_LENGTH:-$max_response_length}
rm_max_num_seqs=${HERO_RM_MAX_NUM_SEQS:-128}
rm_max_num_batched_tokens=${HERO_RM_MAX_NUM_BATCHED_TOKENS:-$((rm_prompt_length + rm_response_length))}
experiment_name=${HERO_EXPERIMENT_NAME:-qwen3_4b_hero_8x24gb}
loggers=${HERO_LOGGERS:-'["console"]'}

# Dense RM used by HERO
dense_rm_model=${HERO_DENSE_RM_MODEL:-nvidia/AceMath-7B-RM}
if [[ "$dense_rm_model" == "AceMath/AceMath-7B-RM" ]]; then
    echo "HERO_DENSE_RM_MODEL=AceMath/AceMath-7B-RM is invalid; using nvidia/AceMath-7B-RM instead." >&2
    dense_rm_model="nvidia/AceMath-7B-RM"
fi

if [[ "$dense_rm_model" == "nvidia/AceMath-7B-RM" ]] \
    && [[ "$rm_enable_resource_pool" != "True" ]] \
    && [[ "$rm_tp_size" == "1" ]]; then
    echo "HERO_RM_TP_SIZE=1 is not supported for colocated $dense_rm_model on the shared 8-GPU training pool." >&2
    echo "It launches one full RM replica per training GPU and can exhaust host RAM before training starts." >&2
    echo "Use HERO_RM_TP_SIZE>=2, or move the reward model to a separate resource pool." >&2
    exit 1
fi

if [[ "$dense_rm_model" == "nvidia/AceMath-7B-RM" ]] \
    && [[ "$rm_enable_resource_pool" != "True" ]] \
    && [[ "$rollout_tp_size" == "1" ]]; then
    if awk "BEGIN { exit !($rollout_gpu_memory_utilization < 0.5) }"; then
        echo "HERO_ROLLOUT_GPU_MEMORY_UTILIZATION=$rollout_gpu_memory_utilization is too low for colocated actor rollout with $dense_rm_model." >&2
        echo "Use HERO_ROLLOUT_TP_SIZE>=2, or set HERO_ROLLOUT_GPU_MEMORY_UTILIZATION>=0.5." >&2
        exit 1
    fi
fi

if [[ "$dense_rm_model" == "nvidia/AceMath-7B-RM" ]] && [[ "$rm_tp_size" == "1" ]]; then
    if awk "BEGIN { exit !($rm_gpu_memory_utilization < 0.6) }"; then
        echo "HERO_RM_GPU_MEMORY_UTILIZATION=$rm_gpu_memory_utilization is too low for $dense_rm_model with HERO_RM_TP_SIZE=1." >&2
        echo "Use HERO_RM_GPU_MEMORY_UTILIZATION>=0.6, or set HERO_RM_TP_SIZE=2 to shard the reward model." >&2
        exit 1
    fi
fi

for required_path in "$hero_train_path" "$hero_val_path"; do
    if [[ ! -f "$required_path" ]]; then
        echo "Missing HERO data file: $required_path" >&2
        exit 1
    fi
done

python3 -m verl.trainer.main_ppo \
    algorithm.adv_estimator=grpo \
    data.train_files="['$hero_train_path']" \
    data.val_files="['$hero_val_path']" \
    data.train_batch_size="$train_batch_size" \
    data.max_prompt_length="$max_prompt_length" \
    data.max_response_length="$max_response_length" \
    data.filter_overlong_prompts=True \
    data.truncation='error' \
    actor_rollout_ref.model.path="$model_path" \
    actor_rollout_ref.actor.optim.lr=1e-6 \
    actor_rollout_ref.model.use_remove_padding=True \
    actor_rollout_ref.model.enable_gradient_checkpointing=True \
    actor_rollout_ref.actor.ppo_mini_batch_size="$ppo_mini_batch_size" \
    actor_rollout_ref.actor.ppo_micro_batch_size_per_gpu="$ppo_micro_batch_size" \
    actor_rollout_ref.actor.use_kl_loss=True \
    actor_rollout_ref.actor.kl_loss_coef=0.001 \
    actor_rollout_ref.actor.kl_loss_type=low_var_kl \
    actor_rollout_ref.rollout.name=vllm \
    actor_rollout_ref.rollout.gpu_memory_utilization="$rollout_gpu_memory_utilization" \
    actor_rollout_ref.rollout.max_num_seqs="$rollout_max_num_seqs" \
    actor_rollout_ref.rollout.max_num_batched_tokens="$rollout_max_num_batched_tokens" \
    actor_rollout_ref.rollout.log_prob_micro_batch_size_per_gpu="$rollout_log_prob_micro_batch_size" \
    actor_rollout_ref.rollout.tensor_model_parallel_size="$rollout_tp_size" \
    actor_rollout_ref.rollout.n="$rollout_n" \
    actor_rollout_ref.ref.log_prob_micro_batch_size_per_gpu="$ref_log_prob_micro_batch_size" \
    algorithm.use_kl_in_reward=False \
    reward.reward_manager.name=hero \
    reward.reward_model.enable=True \
    reward.reward_model.enable_resource_pool="$rm_enable_resource_pool" \
    reward.reward_model.n_gpus_per_node="$rm_gpus" \
    reward.reward_model.nnodes="$rm_nodes" \
    reward.reward_model.model_path="$dense_rm_model" \
    reward.reward_model.rollout.name=vllm \
    reward.reward_model.rollout.tensor_model_parallel_size="$rm_tp_size" \
    reward.reward_model.rollout.gpu_memory_utilization="$rm_gpu_memory_utilization" \
    reward.reward_model.rollout.max_num_seqs="$rm_max_num_seqs" \
    reward.reward_model.rollout.max_num_batched_tokens="$rm_max_num_batched_tokens" \
    reward.reward_model.rollout.prompt_length="$rm_prompt_length" \
    reward.reward_model.rollout.response_length="$rm_response_length" \
    reward.reward_kwargs.hero.alpha=0.1 \
    reward.reward_kwargs.hero.beta=0.1 \
    reward.reward_kwargs.hero.w_min=0.4 \
    reward.reward_kwargs.hero.w_max=3.0 \
    reward.reward_kwargs.hero.k=6.0 \
    trainer.critic_warmup=0 \
    trainer.logger="$loggers" \
    trainer.project_name='verl_hero_grpo' \
    trainer.experiment_name="$experiment_name" \
    trainer.n_gpus_per_node="$trainer_gpus" \
    trainer.nnodes="$trainer_nodes" \
    trainer.save_freq=20 \
    trainer.test_freq=5 \
    trainer.total_epochs=20 $@
